public static boolean solve(long[] nums1) {
    int N = nums1.length;

    // If N=1, nums2[0] must be nums1[0], which trivially satisfies the condition.
    if (N == 1) {
        return true;
    }

    // Count the number of odd elements (C_O)
    int oddCount = 0;
    for (long num : nums1) {
        // Since nums1[i] >= 1, this correctly checks parity.
        if ((num & 1) != 0) { 
            oddCount++;
        }
    }

    // Check feasibility for T=0 (Target Even)
    // T=0 is feasible if:
    // 1. All elements are even (oddCount == 0).
    // 2. There are at least two odd elements (oddCount >= 2). If we have at least two odds, any odd element nums1[i] can be made even by subtracting another odd element nums1[j] (Odd - Odd = Even).
    boolean T0_feasible = (oddCount == 0 || oddCount >= 2);

    // Check feasibility for T=1 (Target Odd)
    // T=1 is feasible if:
    // 1. There is at least one odd element (oddCount >= 1). 
    //    If an odd element exists (O_k), any even element E_i can become odd by subtracting O_k (Even - Odd = Odd). Odd elements can keep themselves odd.
    boolean T1_feasible = (oddCount >= 1);

    return T0_feasible || T1_feasible;
}

