public class Solution {
    public static boolean solve(long[] nums1) {
        int N = nums1.length;
        if (N == 0) {
            return true;
        }

        int cOdd = 0;
        for (long num : nums1) {
            // Check if the number is odd (num % 2 != 0)
            // Since num is positive, standard % operator works fine for parity check.
            if (num % 2 != 0) {
                cOdd++;
            }
        }

        // T=0: Target Parity = 0 (All Even)
        // This is possible if:
        // 1. All numbers are even (cOdd == 0). We just choose nums2[i] = nums1[i].
        // 2. There are at least two odd numbers (cOdd >= 2). 
        //    If nums1[i] is odd, we choose nums2[i] = nums1[i] - nums1[j] where nums1[j] is also odd, 
        //    making the result even. If nums1[i] is even, we choose nums2[i] = nums1[i].
        boolean t0_possible = (cOdd == 0 || cOdd >= 2);

        // T=1: Target Parity = 1 (All Odd)
        // This is possible if there is at least one odd number (cOdd >= 1).
        // If nums1[i] is odd, we choose nums2[i] = nums1[i].
        // If nums1[i] is even, we must choose nums2[i] = nums1[i] - nums1[j] where nums1[j] is odd, 
        // making the result odd. This requires cOdd >= 1.
        boolean t1_possible = (cOdd >= 1);

        // We return true if either target parity is achievable.
        return t0_possible || t1_possible;
    }
}
