public static boolean solve(long[] nums1) {
    int N = nums1.length;
    int C0 = 0; // Count of even numbers
    int C1 = 0; // Count of odd numbers

    for (long x : nums1) {
        if (x % 2 == 0) {
            C0++;
        } else {
            C1++;
        }
    }

    // Helper lambda/local function to check if a target parity T (0=Even, 1=Odd) is achievable
    java.util.function.Function<Integer, Boolean> canAchieve = new java.util.function.Function<Integer, Boolean>() {
        @Override
        public Boolean apply(Integer T) {
            for (int i = 0; i < N; i++) {
                int Pi = (int)(nums1[i] % 2);

                // 1. Check Choice 1: nums2[i] = nums1[i]
                if (Pi == T) {
                    continue; // Success for index i
                }

                // 2. Check Choice 2: nums2[i] = nums1[i] - nums1[j], j != i
                // We need Pj such that Pi ^ Pj = T, so Pj = T ^ Pi
                int Preq = T ^ Pi;
                boolean foundJ = false;

                if (Pi == 0) { // nums1[i] is Even
                    if (Preq == 0) { // Need Pj = 0 (Even)
                        // Need at least one other even number
                        if (C0 >= 2) {
                            foundJ = true;
                        }
                    } else { // Need Pj = 1 (Odd)
                        // Need at least one odd number
                        if (C1 >= 1) {
                            foundJ = true;
                        }
                    }
                } else { // nums1[i] is Odd (Pi == 1)
                    if (Preq == 0) { // Need Pj = 0 (Even)
                        // Need at least one even number
                        if (C0 >= 1) {
                            foundJ = true;
                        }
                    } else { // Need Pj = 1 (Odd)
                        // Need at least one other odd number
                        if (C1 >= 2) {
                            foundJ = true;
                        }
                    }
                }

                if (!foundJ) {
                    return false; // Cannot satisfy parity T for index i
                }
            }
            return true; // Satisfied for all indices
        }
    };

    // Check if all Even (T=0) OR all Odd (T=1) is possible
    return canAchieve.apply(0) || canAchieve.apply(1);
