public static boolean solve(long[] nums1) {
    int n = nums1.length;

    // Helper function to check if a target parity T (0 for even, 1 for odd) is achievable for all elements
    java.util.function.Predicate<Integer> checkParity = (T) -> {
        for (int i = 0; i < n; i++) {
            // P_i is the parity of nums1[i]
            int P_i = (int) (nums1[i] % 2);

            // Case 1: Use nums1[i] directly
            if (P_i == T) {
                continue; // Satisfied for this i
            }

            // Case 2: Must use subtraction: nums2[i] = nums1[i] - nums1[j]
            // We require P(nums1[i] - nums1[j]) = T
            // P_i XOR P_j = T
            // We need P_j = T XOR P_i

            int required_P_j = T ^ P_i;

            boolean found_j = false;
            for (int j = 0; j < n; j++) {
                if (i == j) {
                    continue;
                }

                // P_j is the parity of nums1[j]
                int P_j = (int) (nums1[j] % 2);

                if (P_j == required_P_j) {
                    found_j = true;
                    break;
                }
            }

            if (!found_j) {
                return false; // Cannot satisfy target parity T for index i
            }
        }
        return true; // All indices satisfied for target parity T
    };

    // Check if all elements can be made Even (T=0) OR all elements can be made Odd (T=1)
    return checkParity.test(0) || checkParity.test(1);
}

